import{_ as a,c as t,a1 as i,o}from"./chunks/framework.DiyHpDmR.js";const u=JSON.parse('{"title":"Istio 集成","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/istio.md","filePath":"deploy/istio.md","lastUpdated":1782643526000}'),s={name:"deploy/istio.md"};function l(n,e,c,r,d,p){return o(),t("div",null,e[0]||(e[0]=[i(`<h1 id="istio-集成" tabindex="-1">Istio 集成 <a class="header-anchor" href="#istio-集成" aria-label="Permalink to &quot;Istio 集成&quot;">​</a></h1><p>Istio 是 Firefly 云原生规模化阶段的主要服务治理承接方。当前文档说明集成边界：业务服务保持 <code>go-layout</code> 分层和 <code>go-micro</code> 上下文模型，流量治理、入口鉴权和服务发现逐步由 Istio / Envoy 承接。</p><h2 id="集成目标" tabindex="-1">集成目标 <a class="header-anchor" href="#集成目标" aria-label="Permalink to &quot;集成目标&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client</span></span>
<span class="line"><span>  -&gt; Istio IngressGateway</span></span>
<span class="line"><span>  -&gt; Envoy ext_authz</span></span>
<span class="line"><span>  -&gt; authz</span></span>
<span class="line"><span>  -&gt; Service Sidecar</span></span>
<span class="line"><span>  -&gt; Go 业务服务</span></span></code></pre></div><p>核心原则：</p><ul><li>业务服务不把网关逻辑写进 Service 层。</li><li>鉴权数据面继续使用标准 Envoy ext_authz。</li><li>route facts 继续为 <code>app_id</code>、<code>method</code>、<code>path</code>。</li><li>Firefly 身份入口继续是 <code>x-firefly-user-authority</code>、<code>x-firefly-service-authority</code> 和 <code>x-firefly-authz-sign</code>。</li><li>Trace 使用 W3C Trace Context：<code>traceparent</code>、<code>tracestate</code>、<code>baggage</code>。</li></ul><h2 id="authz" tabindex="-1">authz <a class="header-anchor" href="#authz" aria-label="Permalink to &quot;authz&quot;">​</a></h2><p>在 Istio 中，authz 可以作为 External Authorization 服务接入。它的职责不变：</p><ul><li>校验用户 authority 和服务 authority。</li><li>执行 Casbin 判定。</li><li>allow 后写入普通上下文和短 TTL <code>x-firefly-authz-sign</code>。</li><li>不签发用户 token 或服务 token。</li></ul><p>如果 authz 不可达，推荐保持 fail-close。生产环境应通过多实例、健康检查和清晰的错误监控保证可用性。</p><h2 id="业务服务" tabindex="-1">业务服务 <a class="header-anchor" href="#业务服务" aria-label="Permalink to &quot;业务服务&quot;">​</a></h2><p>Go 业务服务继续使用：</p><ul><li><code>gm.NewServiceContextUnaryInterceptor</code> 构造 <code>service.Context</code>。</li><li>可选 <code>authz_verification</code> 加载 Ed25519 公钥并本地验签。</li><li><code>go-micro/invocation</code> 统一处理出站 metadata 白名单、用户 authority 透传和 service authority 覆盖。</li></ul><h2 id="迁移注意" tabindex="-1">迁移注意 <a class="header-anchor" href="#迁移注意" aria-label="Permalink to &quot;迁移注意&quot;">​</a></h2><ul><li>不要把裸机场景的 <code>sidecar-agent</code> admin API 直接带入 Pod 内作为必需依赖。</li><li>不要恢复业务服务直接操作注册中心 SDK 的旧模式。</li><li>原 <code>api-gateway</code> 中与 north-south 入口相关的能力，在 Istio 模式下应映射到 IngressGateway、VirtualService、EnvoyFilter 或等价平台能力。</li><li>manifest 和 descriptor 仍可作为接口事实、转码和治理输入。</li></ul>`,15)]))}const f=a(s,[["render",l]]);export{u as __pageData,f as default};
